mapper.select:
SELECT count(DISTINCT DATE(created_time)) FROM orders

    created_time >= #{startDate}
    AND created_time <= #{endDate}

SELECT DATE(created_time) as "date", COUNT(*) as "orderCount", COALESCE(SUM(total_amount), 0) as "revenue" FROM orders
"stateId" NOT IN ('CANCELLED', 'FAILED') AND created_time >= #{startDate} AND created_time <= #{endDate}
GROUP BY DATE(created_time) ORDER BY "date" ASC ${pagination}
